diff --git a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
index 550f095b26ba..8360f3193809 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
@@ -1275,6 +1275,7 @@ Instruction *InstCombinerImpl::visitShl(BinaryOperator &I) {
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
   if (Value *V = simplifyLShrInst(I.getOperand(0), I.getOperand(1), I.isExact(),
                                   SQ.getWithInstruction(&I)))
@@ -1413,6 +1414,10 @@ Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
         }
       } else {
         assert(*C1 == ShAmtC);
+        if (cast<BinaryOperator>(Op0)->hasNoUnsignedWrap()) {
+          // (X <<nuw C) >>u C --> X
+          return replaceInstUsesWith(I, X);
+        }
         // (X << C) >>u C --> X & (-1 >>u C)
         APInt Mask(APInt::getLowBitsSet(BitWidth, BitWidth - ShAmtC));
         return BinaryOperator::CreateAnd(X, ConstantInt::get(Ty, Mask));
@@ -1597,6 +1602,55 @@ Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
       Value *And = Builder.CreateAnd(BoolX, BoolY);
       return new ZExtInst(And, Ty);
     }
+
+    // (lshr X, C) + (and X, (1 << C) - 1)  -->  X + (lshr X, C) * (-(2^C - 1))
+    // when the add has nuw and nsw.
+    //
+    // This is valid because:
+    // - Let H = X >> C (high bits shifted down)
+    // - Let L = X & ((1 << C) - 1) (low C bits)
+    // - H has zeros in low C bits, L has zeros in high bits
+    // - H + L doesn't overflow (guaranteed by nuw/nsw)
+    // - X = H * (1 << C) + L, so H + L = X - H * ((1 << C) - 1)
+    if (I.hasOneUse()) {
+      User *U = *I.user_begin();
+      auto *AddI = dyn_cast<BinaryOperator>(U);
+      if (AddI && AddI->getOpcode() == Instruction::Add &&
+          AddI->hasNoUnsignedWrap() && AddI->hasNoSignedWrap()) {
+        Value *Other = AddI->getOperand(0) == &I ? AddI->getOperand(1)
+                                                 : AddI->getOperand(0);
+        APInt Mask = APInt::getLowBitsSet(BitWidth, ShAmtC);
+        if (match(Other,
+                  m_OneUse(m_c_And(m_Specific(Op0), m_SpecificInt(Mask))))) {
+          // (lshr X, C) + (and X, Mask) --> X + (lshr X, C) * (-(2^C - 1))
+          APInt MulCVal = APInt(BitWidth, 1).shl(ShAmtC) - 1;
+          MulCVal = -MulCVal; // -(2^C - 1)
+
+          // Create instructions without inserting
+          auto *NewMul =
+              BinaryOperator::CreateMul(&I, ConstantInt::get(Ty, MulCVal));
+          auto *NewAdd = BinaryOperator::CreateAdd(NewMul, Op0);
+
+          // Insert after the lshr to maintain proper dominance
+          NewMul->insertAfter(&I);
+          NewAdd->insertAfter(NewMul);
+
+          // Add to worklist for further processing
+          Worklist.push(NewMul);
+          Worklist.push(NewAdd);
+
+          // Replace uses of the old add with the new add
+          replaceInstUsesWith(*AddI, NewAdd);
+
+          // Erase old instructions
+          Instruction *AndI = cast<Instruction>(Other);
+          eraseInstFromFunction(*AddI);
+          eraseInstFromFunction(*AndI);
+
+          return nullptr; // lshr doesn't change
+        }
+      }
+    }
   }

   const SimplifyQuery Q = SQ.getWithInstruction(&I);
@@ -1604,10 +1658,17 @@ Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
     return &I;

   // Transform  (x << y) >> y  to  x & (-1 >> y)
-  if (match(Op0, m_OneUse(m_Shl(m_Value(X), m_Specific(Op1))))) {
-    Constant *AllOnes = ConstantInt::getAllOnesValue(Ty);
-    Value *Mask = Builder.CreateLShr(AllOnes, Op1);
-    return BinaryOperator::CreateAnd(Mask, X);
+  // If the shift has no unsigned wrap, the result is just X.
+  if (match(Op0, m_Shl(m_Value(X), m_Specific(Op1)))) {
+    if (cast<BinaryOperator>(Op0)->hasNoUnsignedWrap()) {
+      // (X <<nuw Y) >>u Y --> X
+      return replaceInstUsesWith(I, X);
+    }
+    if (Op0->hasOneUse()) {
+      Constant *AllOnes = ConstantInt::getAllOnesValue(Ty);
+      Value *Mask = Builder.CreateLShr(AllOnes, Op1);
+      return BinaryOperator::CreateAnd(Mask, X);
+    }
   }

   // Transform  (-1 << y) >> y  to -1 >> y
@@ -1638,6 +1699,7 @@ Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
   return nullptr;
 }

+
 Instruction *
 InstCombinerImpl::foldVariableSignZeroExtensionOfVariableHighBitExtract(
     BinaryOperator &OldAShr) {
